const chartConfig: ChartConfig = {
  revenue: { label: "Revenue", color: "hsl(var(--chart-1))" },
  expenses: { label: "Expenses", theme: { light: "#e11d48", dark: "#fb7185" } }
}

import {
  ChartContainer, ChartTooltip, ChartTooltipContent,
  ChartLegendInteractive, useChartLegendInteractive,
  CHART_DEFAULT_MARGIN, CHART_DEFAULT_YAXIS_WIDTH, CHART_DEFAULT_PLOT_LEFT_OFFSET,
  type ChartConfig,
} from "@/components/ui/chart"

const chartConfig: ChartConfig = {
  count: { label: "Dispute Count", color: "var(--color-chart-1)" },
  amount: { label: "Dollar Amount", color: "var(--color-chart-2)" },
}

function MyChart({ data }) {
  const legend = useChartLegendInteractive(chartConfig)

  return (
    <div className="flex flex-col gap-6">
      <ChartContainer config={chartConfig}>
        <ComposedChart data={data} margin={CHART_DEFAULT_MARGIN}>
          <CartesianGrid vertical={false} />
          <XAxis dataKey="month" />
          <YAxis width={CHART_DEFAULT_YAXIS_WIDTH} />
          <ChartTooltip content={<ChartTooltipContent />} />
          <Bar dataKey="count" fill="var(--color-count)" hide={legend.isHidden("count")} />
          <Line dataKey="amount" stroke="var(--color-amount)" hide={legend.isHidden("amount")} />
        </ComposedChart>
      </ChartContainer>
      {/* paddingLeft aligns the legend with the plot area's 0-axis */}
      <div className="flex flex-wrap items-center justify-start gap-x-4 gap-y-2" style={{ paddingLeft: CHART_DEFAULT_PLOT_LEFT_OFFSET }}>
        <ChartLegendInteractive config={chartConfig} legend={legend} />
        <Button variant="outline" size="xs" onClick={legend.reset} className={legend.hasHidden ? "visible" : "invisible"}>Reset</Button>
      </div>
    </div>
  )
}
